import { createSlice } from '@reduxjs/toolkit';


let initialState = {
	isLogin:false,
	isLoginFormOpen:false,
	isRegisterActive:false
}

const accountSlice = createSlice({
	name:'account',
	initialState,
	reducers:{
		handleLoginAndOut:state => {
			state.isLogin = !state.isLogin
		},
		openLoginForm:(state) => {
			state.isLoginFormOpen = !state.isLoginFormOpen
		},
		switchLoginToRegister:(state) => {
			state.isRegisterActive = !state.isRegisterActive
		}
	}
})

export const {openLoginForm, closeLoginForm, switchLoginToRegister, handleLoginAndOut} = accountSlice.actions
export const accountSelector = state => state.account
export default accountSlice.reducer
